const input = $input.first().json;
const action = input.action || 'search_pages';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.notion&cred_key=eq.notion_token&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'Notion integration token not configured. Use add_credential to set it up.' } }];
}

const token = creds[0].cred_value;
const API_BASE = 'https://api.notion.com/v1';
const apiHeaders = {
  'Authorization': 'Bearer ' + token,
  'Content-Type': 'application/json',
  'Notion-Version': '2022-06-28'
};

// Helper: extract plain text from rich_text array
function richTextToPlain(rt) {
  if (!rt || !Array.isArray(rt)) return '';
  return rt.map(t => t.plain_text || t.text?.content || '').join('');
}

// Helper: convert block to text
function blockToText(block) {
  const type = block.type;
  if (!type) return '';
  const data = block[type];
  if (!data) return '';

  const text = richTextToPlain(data.rich_text);

  switch (type) {
    case 'heading_1': return '# ' + text;
    case 'heading_2': return '## ' + text;
    case 'heading_3': return '### ' + text;
    case 'paragraph': return text;
    case 'bulleted_list_item': return '- ' + text;
    case 'numbered_list_item': return '1. ' + text;
    case 'to_do': return (data.checked ? '[x] ' : '[ ] ') + text;
    case 'quote': return '> ' + text;
    case 'code': return '```' + (data.language || '') + '\n' + text + '\n```';
    case 'divider': return '---';
    case 'callout': return '> ' + (data.icon?.emoji || '') + ' ' + text;
    case 'toggle': return '▸ ' + text;
    case 'image':
      const url = data.file?.url || data.external?.url || '';
      return url ? '[Image](' + url + ')' : '[Image]';
    default: return text || '';
  }
}

// === search_pages ===
if (action === 'search_pages') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (search term).' } }];

  try {
    const body = {
      query: query,
      filter: { property: 'object', value: 'page' },
      page_size: 10
    };

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/search',
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    const pages = resp.results || [];
    if (pages.length === 0) {
      return [{ json: { result: 'No pages found for "' + query + '".' } }];
    }

    let result = 'Found ' + pages.length + ' page(s):\n\n';
    for (const p of pages) {
      const title = p.properties?.title?.title
        ? richTextToPlain(p.properties.title.title)
        : (p.properties?.Name?.title
          ? richTextToPlain(p.properties.Name.title)
          : 'Untitled');
      result += '- **' + title + '**\n';
      result += '  ID: ' + p.id + '\n';
      if (p.url) result += '  URL: ' + p.url + '\n';
      result += '  Last edited: ' + (p.last_edited_time || '?') + '\n\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Search failed: ' + err.message } }];
  }

// === read_page ===
} else if (action === 'read_page') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];

  try {
    // Get page metadata
    const page = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/pages/' + pageId,
      headers: apiHeaders
    });

    let title = 'Untitled';
    if (page.properties) {
      for (const key of Object.keys(page.properties)) {
        const prop = page.properties[key];
        if (prop.type === 'title' && prop.title) {
          title = richTextToPlain(prop.title);
          break;
        }
      }
    }

    // Get page content (blocks)
    const blocks = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/blocks/' + pageId + '/children?page_size=100',
      headers: apiHeaders
    });

    let content = '# ' + title + '\n\n';
    if (blocks.results) {
      for (const block of blocks.results) {
        const line = blockToText(block);
        if (line) content += line + '\n\n';
      }
    }

    let result = content.trim();
    result += '\n\n---\nPage ID: ' + pageId;
    if (page.url) result += '\nURL: ' + page.url;
    result += '\nLast edited: ' + (page.last_edited_time || '?');

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to read page: ' + err.message } }];
  }

// === create_page ===
} else if (action === 'create_page') {
  const title = input.title;
  if (!title) return [{ json: { error: 'Parameter "title" is required.' } }];

  try {
    const body = {
      properties: {
        title: {
          title: [{ type: 'text', text: { content: title } }]
        }
      }
    };

    // Set parent
    if (input.parent_id) {
      body.parent = { page_id: input.parent_id };
    } else {
      // Search for a default workspace page or use workspace
      body.parent = { page_id: input.parent_id || '' };
      // Try workspace parent if no parent_id
      if (!input.parent_id) {
        // Find first available page to use as parent
        const searchResp = await helpers.httpRequest({
          method: 'POST',
          url: API_BASE + '/search',
          headers: apiHeaders,
          body: JSON.stringify({ filter: { property: 'object', value: 'page' }, page_size: 1 })
        });
        if (searchResp.results && searchResp.results.length > 0) {
          body.parent = { page_id: searchResp.results[0].id };
        } else {
          return [{ json: { error: 'No parent page found. Please share at least one page with the integration, or provide a parent_id.' } }];
        }
      }
    }

    // Add content via markdown if provided
    if (input.content) {
      body.children = [];
      const lines = input.content.split('\n');
      for (const line of lines) {
        if (!line.trim()) continue;
        let block;
        if (line.startsWith('### ')) {
          block = { object: 'block', type: 'heading_3', heading_3: { rich_text: [{ type: 'text', text: { content: line.substring(4) } }] } };
        } else if (line.startsWith('## ')) {
          block = { object: 'block', type: 'heading_2', heading_2: { rich_text: [{ type: 'text', text: { content: line.substring(3) } }] } };
        } else if (line.startsWith('# ')) {
          block = { object: 'block', type: 'heading_1', heading_1: { rich_text: [{ type: 'text', text: { content: line.substring(2) } }] } };
        } else if (line.startsWith('- ') || line.startsWith('* ')) {
          block = { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: line.substring(2) } }] } };
        } else if (line.startsWith('> ')) {
          block = { object: 'block', type: 'quote', quote: { rich_text: [{ type: 'text', text: { content: line.substring(2) } }] } };
        } else if (line === '---') {
          block = { object: 'block', type: 'divider', divider: {} };
        } else {
          block = { object: 'block', type: 'paragraph', paragraph: { rich_text: [{ type: 'text', text: { content: line } }] } };
        }
        body.children.push(block);
      }
    }

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/pages',
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    let result = 'Page created: ' + title;
    result += '\nID: ' + resp.id;
    if (resp.url) result += '\nURL: ' + resp.url;

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create page: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_pages, read_page, or create_page.' } }];
}
